const crypto = require('crypto');
const { URLSearchParams } = require('url');
const item = $input.first();
const headers = item.json.headers || {};

let rawBody = '';
if (typeof item.json.body === 'string') {
  rawBody = item.json.body;
} else if (item.binary && item.binary.data && item.binary.data.data) {
  rawBody = Buffer.from(item.binary.data.data, 'base64').toString('utf8');
} else if (item.json.rawBody) {
  rawBody = typeof item.json.rawBody === 'string' ? item.json.rawBody : Buffer.from(item.json.rawBody).toString('utf8');
} else if (item.json.body && typeof item.json.body === 'object') {
  rawBody = new URLSearchParams(item.json.body).toString();
}

const signingSecret = $env.SLACK_SIGNING_SECRET || '';
if (signingSecret) {
  const ts = headers['x-slack-request-timestamp'] || '';
  const sig = headers['x-slack-signature'] || '';
  if (!ts || !sig) throw new Error('Missing Slack signature headers');
  if (Math.abs(Math.floor(Date.now()/1000) - Number(ts)) > 300) throw new Error('Stale Slack request');
  const expected = 'v0=' + crypto.createHmac('sha256', signingSecret).update('v0:' + ts + ':' + rawBody).digest('hex');
  const a = Buffer.from(expected);
  const b = Buffer.from(sig);
  if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) throw new Error('Bad Slack signature');
}

const params = new URLSearchParams(rawBody);
const payload = JSON.parse(params.get('payload') || '{}');
const action = (payload.actions || [])[0] || {};
let actionValue = {};
try { actionValue = JSON.parse(action.value || '{}'); } catch (e) {}
const user = payload.user || {};

return [{ json: {
  taskId: actionValue.taskId || '',
  assignedUserId: actionValue.assignedUserId || '',
  slackUserId: user.id || '',
  slackUserName: user.username || user.name || '',
  actionId: action.action_id || '',
  responseUrl: payload.response_url || ''
} }];

const parsed = $('Verify Signature & Parse').first().json;
const espoResult = $input.first() ? ($input.first().json || {}) : {};
const success = !!espoResult.id;
const emoji = success ? '✅' : '⚠️';
const label = success ? 'Acknowledged — In Progress' : 'Acknowledged (CRM update pending)';
const ts = Math.floor(Date.now()/1000);
const blocks = [
  { type: 'section', text: { type: 'mrkdwn', text: emoji + ' *' + label + '*\n_Acknowledged by <@' + parsed.slackUserId + '> <!date^' + ts + '^{date_short_pretty} at {time}|just now>_' } },
  { type: 'actions', elements: [
    { type: 'button', text: { type: 'plain_text', text: '🔗 Open in CRM', emoji: true }, url: 'https://rrespocrm-rsg-u69864.vm.elestio.app/#Task/view/' + parsed.taskId }
  ]}
];
return [{ json: { response_url: parsed.responseUrl, text: emoji + ' ' + label, blocks: blocks } }];
